VALUES
  ('judicial-57112235-moex-00417', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人參加作業者，監獄應給與勞作金，有關勞作金之計算，下列敘述何者錯誤？', '["勞作金之計算依受刑人實際作業時間及勞動能率合併計算", "勞動能率勞作金總額計算方式，按勞作金總額提70%計算之", "作業時間採點數制，每日作業時間4小時以內為1點；超過4小時至8小時以內為3點；超過8小 時至12小時以內為5點", "勞動能率之計算無法按工作數量或日數計算時，由作業承辦人員斟酌作業性質等情形，提教輔小組 審議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00418', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為促使受刑人於執行期間維持身心健康，監獄應妥予安排受刑人運動，依監獄行刑法有關受刑人運動 之相關規定，下列何者錯誤？', '["如無特殊事由，應給予受刑人每日運動半小時", "運動處所以安排於戶外為原則", "必要時，得使其於室內適當處所從事運動", "監獄應提供受刑人適當之運動場地、器材及設備"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00419', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人從事自主監外作業之條件，下列敘述何者錯誤？', '["在監執行逾1個月", "刑期7年以下，殘餘刑期未逾2年或2年內可達陳報假釋條件", "刑期逾7年，殘餘刑期未逾1年或1年內可達陳報假釋條件", "最近6個月內無妨害監獄秩序或安全之行為而受懲罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00420', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人監禁時之教化輔導管理業務，下列敘述何者錯誤？', '["監獄應按監內設施情形，劃分區域，實施受刑人分區管理教化工作", "指派監內教化、作業、戒護及相關人員組成分區教輔小組", "教輔小組，應每月至少開會1次", "監獄應每4個月邀集分區教輔小組成員，舉行全監聯合教輔小組會議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00421', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依外役監條例有關受刑人外役作業時每組人數規定，下列敘述何者正確？', '["每5人以上、20人以下", "每5人以上、25人以下", "每10人以上、20人以下", "每10人以上、30人以下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00422', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '妨害性自主罪受刑人執行期間，監獄為降低其出監後之再犯風險，有關接受強制身心治療或輔導教育 之規定，下列敘述何者正確？', '["入監後，符合刑法第77條所定假釋條件前2年6個月，報請監督機關核定後，將受刑人移至經核 定之執行機關辦理", "強制身心治療或輔導教育，每月最多2小時", "治療評估小組由執行監獄遴聘精神科專科醫師、心理師等專業人員及監獄管教人員至少5人以上組成", "執行機關應落實受刑人釋放前資料轉銜，僅與中央性侵害犯罪防治主管機關聯繫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00423', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '關於收容人購買及吸食香菸之規定，下列敘述何者錯誤？', '["收容人購菸，以2週5包為限，機關得視收容人保管香菸之數量及存放空間，增減之", "收容人領用之香菸，每日合計至多10支，不得私自囤積或為其他不法行為", "收容人購買及吸食之香菸，以機關依法成立之合作社依市價販售或由機關代購之菸品為限，不得由 外界送入或自行攜入", "收容人於移出機關前購買尚未吸食但已拆封之香菸，經移入機關檢查允許後得予攜入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00424', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人因作業或職業訓練致受傷、罹病、重傷、失能或死亡者，應發給補償金，下列敘述何者錯誤？', '["死亡補償金：新臺幣120萬元", "失能補償金：最高金額為新臺幣50萬元", "致重傷者醫療補償金：最高金額不得逾新臺幣30萬元", "致受傷或罹病者醫療補償金：最高金額不得逾新臺幣20萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00425', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關外界為受刑人送入金錢、飲食及必需物品之規定，下列敘述何者正確？', '["外界送入金錢，每一送入人對個別收容人每週限1次，每次以新臺幣1萬元為限。但經機關長官許 可者，不在此限", "收容人在機關內之保管金總額已逾5萬元者，機關長官得限制外界送入金錢之次數或數額", "外界送入飲食給受刑人，每日1次，每次不得逾2公斤。但經機關長官許可者，不在此限", "外界送入必需物品，每一送入人對個別收容人每月限1次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00426', 'judicial-57112235', 'judicial-57112235-moex-112-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄有關外部視察小組行使職權之相關規定，下列敘述何者正確？', '["外部視察小組開會應於機關內召開，得邀請機關人員列席，並得就特定事項邀請機關人員到場說明", "外部視察小組訪談機關人員，應徵得當事人之同意", "外部視察小組訪談機關人員，毋庸經監獄同意得逕行使用錄音器材", "外部視察小組應每年提出視察報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "7bed571ea996", "answer_pdf_sha1": "beb2a64cc59d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
